-- USHS service area ZIP coverage seed for Supabase/PostgreSQL
-- Source: legacy MySQL table `service_areas` from the uploaded PHP database dump.
-- Contains 5,275 ZIP coverage rows, 2,811 distinct city names, 3,238 city/state/region groups, and 28 regions.
-- Run this AFTER supabase/schema.sql in the Supabase SQL Editor.

create extension if not exists pgcrypto;

create table if not exists service_areas (
  id uuid primary key default gen_random_uuid(),
  zip_code text not null,
  city text not null,
  state text not null,
  region text not null,
  is_active boolean not null default true,
  legacy_id integer unique,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (zip_code, city, state, region)
);

create index if not exists service_areas_zip_code_idx on service_areas (zip_code);
create index if not exists service_areas_city_idx on service_areas (city);
create index if not exists service_areas_region_idx on service_areas (region);
create index if not exists service_areas_lookup_idx on service_areas (zip_code, is_active);

on conflict (legacy_id) do update set
  zip_code = excluded.zip_code,
  city = excluded.city,
  state = excluded.state,
  region = excluded.region,
  is_active = excluded.is_active,
  updated_at = excluded.updated_at;
